import numpy as np

def smoothclamp(x, x_min, x_max, N):
    x_clamped = np.clip(x, x_min, x_max)
    t = np.clip((x_clamped - x_min) / (x_max - x_min), 0, 1)

    def binom(n, r):
        if r < 0 or r > n:
            return 0
        if r == 0 or r == n:
            return 1
        if r > n // 2:
            r = n - r
        result = 1
        for i in range(r):
            result = result * (n - i) // (i + 1)
        return result

    result = np.zeros_like(t)
    denom = binom(2*N-1, N-1)

    for k in range(N):
        numer = binom(2*N-1, N+k)
        result += (numer / denom) * np.power(t, N+k) * np.power(1-t, N-k)

    return x_min + result * (x_max - x_min)
