def smoothclamp(x, x_min, x_max, N):
    def binomial(n, k):
        if k < 0 or k > n:
            return 0.0
        result = 1.0
        for i in range(min(k, n - k)):
            result = result * (n - i) / (i + 1)
        return result

    def smoothstep(x, N):
        if N == 1:
            return 3 * x**2 - 2 * x**3
        elif N == 2:
            return 6 * x**5 - 15 * x**4 + 10 * x**3
        elif N == 3:
            return 20 * x**6 - 70 * x**5 + 84 * x**4 - 35 * x**3
        elif N == 4:
            return 70 * x**7 - 280 * x**6 + 420 * x**5 - 280 * x**4 + 70 * x**3
        elif N == 5:
            return 252 * x**8 - 1260 * x**7 + 2520 * x**6 - 2520 * x**5 + 1260 * x**4 - 252 * x**3
        else:
            result = x * 0.0
            for k in range(N + 1):
                coeff = (-1)**k * binomial(N, k)
                term = coeff * np.Abs(x - k)**(2*N) * np.Sign(x - k)
                result = result + term
            return result

    x_normalized = (x - x_min) / (x_max - x_min)
    smooth = smoothstep(x_normalized, N)
